            <tr style="background:var(--bg-tertiary);"><td style="padding:0.75rem;border:1px solid var(--border);">3 gestores</td><td style="padding:0.75rem;border:1px solid var(--border);text-align:center;"><strong>19-39€/mes</strong></td><td style="padding:0.75rem;border:1px solid var(--border);text-align:center;"><strong>23,85€/mes</strong></td></tr>
